import{_ as a,b as d,o,i as r,j as n,g as i,aB as l}from"./chunks/framework._ZAOES46.js";const _=JSON.parse('{"title":"FaTextShiny 流光文字","description":"","frontmatter":{},"headers":[],"relativePath":"components/pro/FaTextShiny.md","filePath":"components/pro/FaTextShiny.md"}'),s={name:"components/pro/FaTextShiny.md"};function h(c,t,p,m,b,u){const e=d("Badge");return o(),r("div",null,[t[0]||(t[0]=n("div",{style:{display:"none"},hidden:"true","aria-hidden":"true","data-nosnippet":""},"Are you an LLM? You can read better optimized documentation at /components/pro/FaTextShiny.md for this page in Markdown format",-1)),i(e,{type:"pro",text:"专业版"}),t[1]||(t[1]=l('<h1 id="fatextshiny-流光文字" tabindex="-1">FaTextShiny 流光文字 <a class="header-anchor" href="#fatextshiny-流光文字" aria-label="Permalink to “FaTextShiny 流光文字”">​</a></h1><p>通过扫光渐变为文字增加持续流动的高光效果，适合做标题、强调词和品牌文案。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>首页标题、Banner 文案、营销口号</li><li>卡片标题中的关键数字或关键字</li><li>行内强调品牌名、动作词、状态词</li><li>需要一点动态感，但不希望页面过度花哨的场景</li></ul><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to “Props”">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>说明</th><th>类型</th><th>默认值</th></tr></thead><tbody><tr><td>duration</td><td>单次扫光动画时长，单位秒</td><td><code>number</code></td><td><code>1.5</code></td></tr><tr><td>delay</td><td>首次开始动画的延迟，单位秒</td><td><code>number</code></td><td><code>1.5</code></td></tr><tr><td>class</td><td>自定义类名，文字颜色由 <code>currentColor</code> 决定</td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td><code>undefined</code></td></tr></tbody></table><h2 id="slots" tabindex="-1">Slots <a class="header-anchor" href="#slots" aria-label="Permalink to “Slots”">​</a></h2><table tabindex="0"><thead><tr><th>名称</th><th>说明</th></tr></thead><tbody><tr><td>default</td><td>要显示的文字或行内内容</td></tr></tbody></table><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ul><li>更适合 1 到 2 行以内的短文字，字数过多时高光会显得分散</li><li>建议搭配较大字号或较粗字重使用，扫光层次会更清晰</li><li>如果背景本身已经很复杂，先确认文字本体仍然有足够可读性</li><li>想强调重点时用它做局部点缀即可，不建议把整段正文都做成扫光效果</li></ul>',10))])}const f=a(s,[["render",h]]);export{_ as __pageData,f as default};
